class TrieNode:
    def __init__(self):
        self.children = {}
        self.is_end_of_word = False

class Trie:
    def __init__(self):
        self.root = TrieNode()

    def insert(self, word):
        node = self.root
        for char in word:
            if char not in node.children:
                node.children[char] = TrieNode()
            node = node.children[char]
        node.is_end_of_word = True

    def filter_text(self, text, mask_char='*'):
        filtered_text_list = list(text)
        n = len(text)

        for i in range(n):
            node = self.root
            j = i
            longest_matched_word_len = 0

            while j < n and text[j] in node.children:
                node = node.children[text[j]]
                if node.is_end_of_word:
                    longest_matched_word_len = j - i + 1
                j += 1

            if longest_matched_word_len > 0:
                for k in range(i, i + longest_matched_word_len):
                    filtered_text_list[k] = mask_char

        return "".join(filtered_text_list)

